B.Lx=new A.bd(B.c1,[B.J5,B.Ik,B.I7,'\ud83d\udcd2 To request a cheque book:\n\n1\ufe0f\u20e3 On the Home screen tap "Accounts"\n2\ufe0f\u20e3 Select "Request Cheque Book"\n3\ufe0f\u20e3 Choose your account\n4\ufe0f\u20e3 Confirm your request\n\n\u2705 Your cheque book will be ready within 3\u20135 business days.','\ud83d\udcd2 \u0644\u0637\u0644\u0628 \u062f\u0641\u062a\u0631 \u0634\u064a\u0643\u0627\u062a:\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 "\u0627\u0644\u062d\u0633\u0627\u0628\u0627\u062a"\n2\ufe0f\u20e3 \u0627\u062e\u062a\u0631 "\u0637\u0644\u0628 \u062f\u0641\u062a\u0631 \u0634\u064a\u0643\u0627\u062a"\n3\ufe0f\u20e3 \u0627\u062e\u062a\u0631 \u062d\u0633\u0627\u0628\u0643\n4\ufe0f\u20e3 \u0623\u0643\u0651\u062f \u0627\u0644\u0637\u0644\u0628\n\n\u2705 \u0633\u064a\u0643\u0648\u0646 \u062f\u0641\u062a\u0631 \u0627\u0644\u0634\u064a\u0643\u0627\u062a \u062c\u0627\u0647\u0632\u0627\u064b \u062e\u0644\u0627\u0644 3-5 \u0623\u064a\u0627\u0645 \u0639\u0645\u0644.','\ud83d\udcd2 Pour demander un ch\xe9quier:\n\n1\ufe0f\u20e3 Sur l\'accueil appuyez "Comptes"\n2\ufe0f\u20e3 S\xe9lectionnez "Demande de ch\xe9quier"\n3\ufe0f\u20e3 Choisissez votre compte\n4\ufe0f\u20e3 Confirmez votre demande\n\n\u2705 Votre ch\xe9quier sera pr\xeat dans 3 \xe0 5 jours ouvrables.'],t.EU)
