B.LA=new A.bd(B.c1,[B.Iq,B.IA,B.JO,'\ud83d\udcb3 Debit Card services:\n\n1\ufe0f\u20e3 On the Home screen tap "Debit Card"\n2\ufe0f\u20e3 You can:\n   \u2022 Request a new card\n   \u2022 View card details\n   \u2022 Freeze / unfreeze your card\n   \u2022 Set spending limits\n\n\u2705 Virtual card is available immediately.\nPhysical card delivery: 5\u20137 business days.','\ud83d\udcb3 \u062e\u062f\u0645\u0627\u062a \u0628\u0637\u0627\u0642\u0629 \u0627\u0644\u062e\u0635\u0645:\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 "\u0628\u0637\u0627\u0642\u0629 \u0627\u0644\u062e\u0635\u0645"\n2\ufe0f\u20e3 \u064a\u0645\u0643\u0646\u0643:\n   \u2022 \u0637\u0644\u0628 \u0628\u0637\u0627\u0642\u0629 \u062c\u062f\u064a\u062f\u0629\n   \u2022 \u0639\u0631\u0636 \u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0628\u0637\u0627\u0642\u0629\n   \u2022 \u062a\u062c\u0645\u064a\u062f / \u0625\u0644\u063a\u0627\u0621 \u062a\u062c\u0645\u064a\u062f \u0627\u0644\u0628\u0637\u0627\u0642\u0629\n   \u2022 \u062a\u062d\u062f\u064a\u062f \u062d\u062f\u0648\u062f \u0627\u0644\u0625\u0646\u0641\u0627\u0642\n\n\u2705 \u0627\u0644\u0628\u0637\u0627\u0642\u0629 \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629 \u0645\u062a\u0627\u062d\u0629 \u0641\u0648\u0631\u0627\u064b.\n\u062a\u0648\u0635\u064a\u0644 \u0627\u0644\u0628\u0637\u0627\u0642\u0629 \u0627\u0644\u0645\u0627\u062f\u064a\u0629: 5-7 \u0623\u064a\u0627\u0645 \u0639\u0645\u0644.','\ud83d\udcb3 Services carte de d\xe9bit:\n\n1\ufe0f\u20e3 Sur l\'accueil appuyez "Carte d\xe9bit"\n2\ufe0f\u20e3 Vous pouvez:\n   \u2022 Demander une nouvelle carte\n   \u2022 Voir les d\xe9tails de la carte\n   \u2022 Geler / d\xe9geler la carte\n   \u2022 D\xe9finir les limites de d\xe9penses\n\n\u2705 Carte virtuelle disponible imm\xe9diatement.\nLivraison carte physique: 5\u20137 jours ouvrables.'],t.EU)
